import { useState, createContext } from 'react'
import axios from 'axios'


const BookContext = createContext()

const BookProvider = ({children}) => {

    const [search, setSearch] = useState({
        query: ''
    })

    const [loading, setLoading] = useState(false)
    const [bookData, setBookData] = useState([])

    const getBookList = async () => {
        setLoading(true);
      
        try {
          const url =
            "https://www.googleapis.com/books/v1/volumes?q=" +
            search.query +
            "&key=" +
            process.env.REACT_APP_GOOGLE_BOOKS_API_KEY +
            "&maxResults=40&printType=books&projection=lite";
          const { data: res } = await axios(url);
      
          if (res && res.items) {
            console.log("Libros sin filtrar:", res.items);
      
            // Filtrar solo los libros con ISBN-10 o ISBN-13
            const filteredBooks = res.items.filter((book) => {
              const industryIdentifiers = book.volumeInfo.industryIdentifiers || [];
      
              return industryIdentifiers.some(
                (identifier) =>
                  (identifier.type === "ISBN_10" || identifier.type === "ISBN_13") &&
                  identifier.identifier !== null
              );
            });
      
            console.log("Libros después del filtrado:", filteredBooks);
      
            setBookData(filteredBooks);
          } else {
            setBookData([]);
          }
        } catch (error) {
          console.error(error);
        } finally {
          setLoading(false);
        }
      };

    const clearBookList = () => {
        setBookData([]);
    };
    

    const [userBooks, setUserBooks] = useState([])

    const [userSearched, setUserSearched] = useState([])



    return (
        <BookContext.Provider value={{ getBookList, clearBookList, bookData, search, setSearch, loading, setLoading, userBooks, setUserBooks, userSearched, setUserSearched }}>
            {children}
        </BookContext.Provider>
    )
}

export { BookProvider }

export default BookContext
